import{_ as o,o as t,c as r,a0 as a}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Import & OCR Problems","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/imports.md","filePath":"troubleshooting/imports.md"}'),i={name:"troubleshooting/imports.md"};function l(s,e,n,h,d,p){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="import-ocr-problems" tabindex="-1">Import &amp; OCR Problems <a class="header-anchor" href="#import-ocr-problems" aria-label="Permalink to &quot;Import &amp; OCR Problems&quot;">​</a></h1><p>Use the symptom below that is closest to what went wrong, then follow the linked fix.</p><h2 id="names-or-numbers-were-read-wrong" tabindex="-1">Names or numbers were read wrong <a class="header-anchor" href="#names-or-numbers-were-read-wrong" aria-label="Permalink to &quot;Names or numbers were read wrong&quot;">​</a></h2><p>Use this path when OCR guessed badly.</p><ul><li>If the screenshot is ordinary and readable, first re-check the row on <a href="./../imports/review-rows.html">Review Import Rows</a>.</li><li>If the screenshot is hard to read, switch provider guidance on <a href="./../imports/choose-provider.html">Choose an Image-Processing Provider</a>. Gemini is the better choice for smaller text, trickier formatting, or harder screenshots.</li><li>If only a few rows are wrong, correct them before accepting on <a href="./../imports/review-rows.html">Review Import Rows</a>.</li></ul><h2 id="i-uploaded-to-the-wrong-event-wrong-date-or-wrong-alliance" tabindex="-1">I uploaded to the wrong event, wrong date, or wrong alliance <a class="header-anchor" href="#i-uploaded-to-the-wrong-event-wrong-date-or-wrong-alliance" aria-label="Permalink to &quot;I uploaded to the wrong event, wrong date, or wrong alliance&quot;">​</a></h2><p>Use the undo path, not manual patching.</p><ol><li>If rows were <strong>not</strong> accepted yet, delete the import normally and upload again.</li><li>If rows <strong>were</strong> accepted, use <a href="./../imports/delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a>.</li><li>If you still want the import draft back afterward, use <a href="./../imports/restore-import.html">Restore a Deleted Import</a>.</li></ol><p>Important: rollback is only guaranteed at the level already documented in <a href="./../imports/delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a>. It does <strong>not</strong> promise to blindly rewind newer unrelated work.</p><h2 id="the-import-is-stuck-failed-or-did-not-finish-cleanly" tabindex="-1">The import is stuck, failed, or did not finish cleanly <a class="header-anchor" href="#the-import-is-stuck-failed-or-did-not-finish-cleanly" aria-label="Permalink to &quot;The import is stuck, failed, or did not finish cleanly&quot;">​</a></h2><p>Start with the simplest safe path.</p><ul><li>If the import shows <code>failed</code>, use a fresh upload and check the provider choice first. See <a href="./../imports/overview.html">How Screenshot Imports Work</a>.</li><li>If you were looking for an in-place reprocess flow, read <a href="./../imports/reprocess.html">Reprocess an Import</a> carefully. In the currently documented behavior, the practical fix is usually a fresh upload instead of rebuilding the same import in place.</li></ul><h2 id="i-accepted-the-wrong-rows" tabindex="-1">I accepted the wrong rows <a class="header-anchor" href="#i-accepted-the-wrong-rows" aria-label="Permalink to &quot;I accepted the wrong rows&quot;">​</a></h2><p>Use the rollback path if live data was written incorrectly.</p><ul><li>If the mistake is small and still in review, fix the row on <a href="./../imports/review-rows.html">Review Import Rows</a>.</li><li>If the wrong rows were already accepted and changed live data, use <a href="./../imports/delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a>.</li><li>If you want the import back as a working draft after rollback, use <a href="./../imports/restore-import.html">Restore a Deleted Import</a>.</li></ul><h2 id="the-page-says-the-session-is-locked" tabindex="-1">The page says the session is locked <a class="header-anchor" href="#the-page-says-the-session-is-locked" aria-label="Permalink to &quot;The page says the session is locked&quot;">​</a></h2><p>This is not an OCR problem. It is an event-instance lock.</p><ul><li>Use <a href="./../how-to/session-lock.html">Locked Instances &amp; Unlock Requests</a>.</li><li>After the unlock is approved, return to the import and continue.</li></ul><h2 id="i-do-not-know-which-guide-i-need" tabindex="-1">I do not know which guide I need <a class="header-anchor" href="#i-do-not-know-which-guide-i-need" aria-label="Permalink to &quot;I do not know which guide I need&quot;">​</a></h2><p>Use this order:</p><ol><li><a href="./../imports/overview.html">How Screenshot Imports Work</a></li><li><a href="./../imports/review-rows.html">Review Import Rows</a></li><li><a href="./../imports/apply-import.html">Accept Rows (Apply an Import)</a></li><li><a href="./../imports/delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a></li></ol>',21)])])}const w=o(i,[["render",l]]);export{m as __pageData,w as default};
